const benefits = [
  {
    icon: '⚡',
    title: 'Devis rapide',
    description: 'Obtenez votre devis personnalisé en moins de 15 minutes. Réponse garantie sous 24h.'
  },
  {
    icon: '🎯',
    title: 'Spécialistes reconnus',
    description: 'Expertise reconnue dans l\'assurance taxi depuis plus de 10 ans. Partenaires avec les meilleures assureurs.'
  },
  {
    icon: '✅',
    title: 'Tous profils acceptés',
    description: 'Nous assurons les profils difficiles : jeune permis, malus, résiliation, historique chargé.'
  },
  {
    icon: '🔄',
    title: 'Résilié / Malus accepté',
    description: 'Pas de refus ! Nous trouvons une solution même avec des antécédents difficiles.'
  }
];

export default function Benefits() {
  return (
    <section className="py-20 bg-white">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-14">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900">
            Pourquoi choisir <span className="text-blue-800">SecureTaxi</span> ?
          </h2>
          <p className="mt-4 text-gray-600 text-lg max-w-2xl mx-auto">
            Nous simplifions l'assurance de votre véhicule professionnel avec un service adapté à vos besoins.
          </p>
        </div>

        <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {benefits.map((benefit, index) => (
            <div 
              key={index} 
              className="card text-center group hover:-translate-y-1"
            >
              <div className="w-14 h-14 bg-blue-100 rounded-2xl flex items-center justify-center mx-auto mb-4 group-hover:bg-yellow-100 transition-colors">
                <span className="text-3xl">{benefit.icon}</span>
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-3">{benefit.title}</h3>
              <p className="text-gray-600">{benefit.description}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
